=<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Weekly Sales Digest</title>
  <style>
    body {
      font-family: Arial, sans-serif;
      color: #333;
      line-height: 1.5;
      margin: 0;
      padding: 0;
      background-color: #f4f4f4;
    }
    .container {
      max-width: 600px;
      margin: 20px auto;
      background-color: #fff;
      padding: 20px;
      border-radius: 8px;
      box-shadow: 0 0 10px rgba(0,0,0,0.1);
      text-align: center;
    }
    h2, h3 {
      color: #2E86C1;
    }
    p {
      margin: 15px 0;
    }
  </style>
</head>
<body>
  <div class="container">
    <h2>Weekly Sales Digest</h2>
    <h3>Dear David,</h3>
    <p>Find attached the latest sales summary for your review:</p>

    <!-- Embed QuickChart -->
    <img src="{{ $json.body.chartUrl }}" alt="Sales Chart" width="100%" style="max-width:550px;"/>

    <!-- Executive summary -->
    <p>{{ $json.body.summary }}</p>

    <p>Best regards,<br/>Your Analytics Team</p>
  </div>
</body>
</html>
